import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import android.util.Base64
import java.security.SecureRandom
import javax.crypto.Cipher
import javax.crypto.spec.SecretKeySpec

class SessionTokenGenerator {
    companion object {
        private const val KEY_ALGORITHM = "AES"
        private const val KEY_SIZE = 256
        private const val IV_SIZE = 128
        private const val SESSION_ID_LENGTH = 32

        fun generateSessionId(): String {
            return Base64.encodeToString(SecureRandom().generateSeed(SESSION_ID_LENGTH), Base64.DEFAULT)
        }

        fun generateToken(sessionId: String): String {
            val keyGenParameterSpec = KeyGenParameterSpec.Builder("session_key", KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT)
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .build()
            val key = KeyStore.getInstance().generateKey(keyGenParameterSpec)
            val iv = SecureRandom().generateSeed(IV_SIZE)
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
